return `🤝 Negotiation Tips for ${crop}:
• Current APMC rate: ₹${price}/kg
• Target asking price: ₹${targetPrice}/kg (+10%)
• Your leverage: ${qty} kg is ${qty > 500 ? "a bulk order — buyers prefer this" : "a smaller lot — consider pooling with nearby farmers"}
• Resilience ${resilience_index}/100 means ${resilience_index >= 70 ? "strong position" : "weaker position — accept fair offers quickly"}.`;
